const FILTERS_CONTAINER=document.querySelector("div.sectional-filters"),CHECKBOXES=FILTERS_CONTAINER.querySelectorAll('input[type="checkbox"]'),SECTIONAL_BITS=Object.freeze({central:1,central_chicago:2,north:4,north_chicago:8,south:16,south_chicago:32,west:64,west_chicago:128});function encodeSectionals(e){let t=0;for(const n of e){const s=SECTIONAL_BITS[n]||0;t=t|s}return t}function decodeSectionals(e){if(!Number.isInteger(e)||e<0||e>255)return decodeSectionals(255);const t=[];for(const[n,s]of Object.entries(SECTIONAL_BITS))(e&s)!==0&&t.push(n);return t}function hideAthleteRows(e){document.querySelectorAll("#preview-athletes tr").forEach(t=>{const n=t.dataset.sectional;t.hidden=!e.includes(n)})}function hideHeadToHeadRows(e){document.querySelectorAll("#preview-head-to-heads tr").forEach(t=>{const n=t.querySelectorAll("td[data-sectional]");if(n.length!==2){t.hidden=!0;return}const s=n[0].dataset.sectional,o=n[1].dataset.sectional,i=e.includes(s)&&e.includes(o);t.hidden=!i})}function onSectionalsChanged(e){const n=encodeSectionals(e),t=new URL(window.location.href);n===255?t.searchParams.delete("filter"):t.searchParams.set("filter",n.toString()),history.replaceState(null,"",t),hideAthleteRows(e),hideHeadToHeadRows(e)}function handleSectionalChange(){const e=Array.from(CHECKBOXES).filter(e=>e.checked).map(e=>e.value);onSectionalsChanged(e)}function parseMaskFromURL(){const n=new URLSearchParams(window.location.search),t=n.get("filter");if(t===null)return 255;const e=Number(t);return!Number.isInteger(e)||e<0||e>255?255:e}function initSectionals(){const t=parseMaskFromURL(),e=decodeSectionals(t);CHECKBOXES.forEach(t=>{t.checked=e.includes(t.value)}),onSectionalsChanged(e)}CHECKBOXES.forEach(e=>{e.addEventListener("change",handleSectionalChange)}),initSectionals()